def gen(rng, size):
    import string
    def word():
        L = rng.randint(1, 7)
        return ''.join(rng.choice(string.ascii_letters) for _ in range(L))
    nw = max(1, min(size, 300))
    nq = max(1, min(size, 300))
    wordlist = [word() for _ in range(nw)]
    queries = []
    vowels = 'aeiou'
    for _ in range(nq):
        if wordlist and rng.random() < 0.5:
            base = rng.choice(wordlist)
            chars = list(base)
            for i in range(len(chars)):
                if rng.random() < 0.3:
                    chars[i] = chars[i].upper() if chars[i].islower() else chars[i].lower()
                if chars[i].lower() in vowels and rng.random() < 0.4:
                    keep = chars[i].isupper()
                    nc = rng.choice(vowels)
                    chars[i] = nc.upper() if keep else nc
            queries.append(''.join(chars))
        else:
            queries.append(word())
    return [wordlist, queries]

