class Solution:
    def spellchecker(self, wordlist, queries):
        vowels = set('aeiou')
        def devowel(w):
            return ''.join('*' if c in vowels else c for c in w.lower())
        res = []
        for q in queries:
            ans = ''
            if q in wordlist:
                ans = q
            else:
                found = ''
                for w in wordlist:
                    if w.lower() == q.lower():
                        found = w
                        break
                if found:
                    ans = found
                else:
                    dq = devowel(q)
                    for w in wordlist:
                        if devowel(w) == dq:
                            found = w
                            break
                    ans = found
            res.append(ans)
        return res

