class Solution:
    def spellchecker(self, wordlist, queries):
        vowels = set('aeiou')
        def devowel(w):
            return ''.join('*' if c in vowels else c for c in w.lower())
        exact = set(wordlist)
        lower_map = {}
        vowel_map = {}
        for w in wordlist:
            lw = w.lower()
            if lw not in lower_map:
                lower_map[lw] = w
            dv = devowel(w)
            if dv not in vowel_map:
                vowel_map[dv] = w
        res = []
        for q in queries:
            if q in exact:
                res.append(q)
            elif q.lower() in lower_map:
                res.append(lower_map[q.lower()])
            elif devowel(q) in vowel_map:
                res.append(vowel_map[devowel(q)])
            else:
                res.append('')
        return res

