var spellchecker = function(wordlist, queries) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const devowel = (w) => w.toLowerCase().split('').map(c => vowels.has(c) ? '*' : c).join('');
    const exact = new Set(wordlist);
    const lowerMap = new Map();
    const vowelMap = new Map();
    for (const w of wordlist) {
        const lw = w.toLowerCase();
        if (!lowerMap.has(lw)) lowerMap.set(lw, w);
        const dv = devowel(w);
        if (!vowelMap.has(dv)) vowelMap.set(dv, w);
    }
    const res = [];
    for (const q of queries) {
        if (exact.has(q)) res.push(q);
        else if (lowerMap.has(q.toLowerCase())) res.push(lowerMap.get(q.toLowerCase()));
        else if (vowelMap.has(devowel(q))) res.push(vowelMap.get(devowel(q)));
        else res.push('');
    }
    return res;
};
